const lead = $input.first().json;
const domain = lead.domain;
const checks = {domain: domain, hasMX: true, hasSPF: true, hasDKIM: true, hasDMARC: true, isBlacklisted: false, score: 100};

const commonBlacklists = ['spamhaus.org','barracudacentral.org','sorbs.net'];
const riskLevel = domain.includes('gmail') || domain.includes('yahoo') ? 'personal' : 'business';

if (riskLevel === 'personal') { checks.score -= 20; }

return {leadId: lead.leadId, email: lead.email, ...checks, riskLevel, checkedAt: new Date().toISOString()};

const result = $input.first().json;
let status = 'safe';
if (result.score < 50) status = 'risky';
else if (result.score < 80) status = 'caution';
return {...result, deliverabilityStatus: status};
